import json, re

# Load business collection data from the provided JSON file path
with open(var_call_3dR2N3GFpsj8tWO8sPYjnnQr, 'r') as f:
    businesses = json.load(f)

review_aggs = var_call_ivZY1HrkZA0nf3emOfTEArj0

# Build mapping from business_ref to state extracted from description
bref_to_state = {}
for b in businesses:
    bid = b.get('business_id')
    desc = b.get('description', '') or ''
    if not bid or not desc:
        continue
    # extract numeric suffix after underscore
    if '_' in bid:
        suffix = bid.split('_', 1)[1]
        bref = 'businessref_' + suffix
    else:
        continue
    m = re.search(r',\s*([A-Z]{2})\b', desc)
    if m:
        state = m.group(1)
        bref_to_state[bref] = state

# Aggregate total reviews and weighted rating numerator by state using review aggregates
state_total_reviews = {}
state_weighted_rating = {}
for r in review_aggs:
    bref = r.get('business_ref')
    if bref not in bref_to_state:
        continue
    state = bref_to_state[bref]
    try:
        rc = int(r.get('review_count', 0))
    except:
        rc = 0
    try:
        avg = float(r.get('avg_rating', 0.0))
    except:
        avg = 0.0
    state_total_reviews[state] = state_total_reviews.get(state, 0) + rc
    state_weighted_rating[state] = state_weighted_rating.get(state, 0.0) + avg * rc

# Find state with highest number of reviews
if not state_total_reviews:
    result = {"state": None, "total_reviews": 0, "average_rating": None}
else:
    max_state = max(state_total_reviews.items(), key=lambda x: x[1])[0]
    total_reviews = state_total_reviews[max_state]
    avg_rating = None
    if total_reviews > 0:
        avg_rating = state_weighted_rating[max_state] / total_reviews
    # round to 4 decimals
    if avg_rating is not None:
        avg_rating = round(avg_rating, 4)
    result = {"state": max_state, "total_reviews": total_reviews, "average_rating": avg_rating}

print("__RESULT__:")
print(json.dumps(result))

