import json, re
with open(var_call_3dR2N3GFpsj8tWO8sPYjnnQr, 'r') as f:
    businesses = json.load(f)
review_aggs = var_call_ivZY1HrkZA0nf3emOfTEArj0

bref_to_state = {}
patterns = [r'in [^,]+,\s*([A-Z]{2})', r',\s*([A-Z]{2}),', r',\s*([A-Z]{2})\b', r'\b([A-Z]{2}) location\b']
for b in businesses:
    bid = b.get('business_id')
    desc = b.get('description','') or ''
    if not bid or not desc:
        continue
    if '_' in bid:
        suffix = bid.split('_',1)[1]
        bref = 'businessref_' + suffix
    else:
        continue
    state = None
    for p in patterns:
        m = re.search(p, desc)
        if m:
            state = m.group(1)
            break
    if state:
        bref_to_state[bref] = state

state_total_reviews = {}
state_weighted = {}
for r in review_aggs:
    bref = r.get('business_ref')
    if bref in bref_to_state:
        st = bref_to_state[bref]
        try:
            rc = int(r.get('review_count',0))
        except:
            rc = 0
        try:
            avg = float(r.get('avg_rating',0.0))
        except:
            avg = 0.0
        state_total_reviews[st] = state_total_reviews.get(st,0) + rc
        state_weighted[st] = state_weighted.get(st,0.0) + avg * rc

# prepare debug info
common = set(r['business_ref'] for r in review_aggs) & set(bref_to_state.keys())
missing = list(set(r['business_ref'] for r in review_aggs) - set(bref_to_state.keys()))[:20]

output = {
    'mapped_brefs_count': len(bref_to_state),
    'common_count': len(common),
    'sample_mapping': dict(list(bref_to_state.items())[:10]),
    'sample_missing_review_brefs': missing,
    'state_total_reviews_sample': state_total_reviews
}

# find max state
if state_total_reviews:
    max_state = max(state_total_reviews.items(), key=lambda x: x[1])[0]
    total = state_total_reviews[max_state]
    avg = round(state_weighted[max_state]/total,4) if total>0 else None
    output['answer'] = {'state': max_state, 'total_reviews': total, 'average_rating': avg}
else:
    output['answer'] = {'state': None, 'total_reviews': 0, 'average_rating': None}

print('__RESULT__:')
print(json.dumps(output))

